/**
 * Belt Harness System
 *
 * AI-powered development harness using local LLMs and Claude.
 * Implements the architecture from hard-harness-example.md.
 */

// Persistence
export {
  addFeature,
  appendProgress,
  createFeaturesFile,
  createProgressFile,
  createRollbackSnapshot,
  initBeltDirectory,
  loadBrainstormBacklog,
  loadBrainstormState,
  logSession,
  readFeatures,
  readProgress,
  restoreRollbackSnapshot,
  saveBrainstormBacklog,
  saveBrainstormState,
  updateFeatureStatus,
  writeFeatures,
  type BrainstormSessionState,
  type Feature,
  type FeaturesFile,
} from './persistence/progress';

// Ollama Client
export {
  OllamaClient,
  REQUIRED_MODELS,
  checkRequiredModels,
  createOllamaClient,
  type OllamaChatMessage,
  type OllamaChatOptions,
  type OllamaChatResponse,
  type OllamaGenerateOptions,
  type OllamaGenerateResponse,
  type OllamaModel,
} from './ollama';

// Download Manager
export {
  OllamaDownloadManager,
  createDownloadManager,
  detectOptimalConcurrency,
  formatBytes,
  type DownloadManagerConfig,
  type DownloadProgress,
  type DownloadResult,
  type ModelDownload,
} from './download-manager';

// Progress UI
export {
  DownloadProgressUI,
  runWithAutoProgress,
  runWithProgressUI,
  runWithSimpleProgress,
  type ProgressUIConfig,
} from './progress-ui';

// Router
export {
  TaskRouter,
  createRouter,
  type RouterOptions,
  type RoutingResult,
  type TaskCategory,
} from './router';

// Agents
export {
  AGENTS,
  collaborativeAnalysis,
  executeAgent,
  getAgent,
  listAgents,
  streamAgent,
  type Agent,
  type AgentExecutionOptions,
  type AgentResponse,
} from './agents';

// Brainstorm System
export {
  BRAINSTORM_PERSONAS,
  BrainstormSession,
  DEFAULT_BRAINSTORM_CONFIG,
  createBrainstormSession,
  getPersona,
  getPersonaIds,
  listPersonas,
  runBrainstorm,
  type BrainstormConfig,
  type BrainstormPhase,
  // Session
  type BrainstormSessionConfig,
  type BrainstormState,
  type Epic,
  type FeatureBacklog,
  type FeatureEvaluation,
  // Personas
  type Persona,
  type PhaseResult,
  // Types
  type ProjectContext,
  type RawFeature,
  type RefinedFeature,
} from './brainstorm';

