     3→/**
     4→ * AgentRC Hook Runner
     5→ *
     6→ * Standalone CLI for evaluating .agentrc.ts rules during Claude Code hooks.
     7→ * Called directly from settings.json without needing local wrapper files.
     8→ *
     9→ * Usage in .claude/settings.json:
    10→ *   { "type": "command", "command": "bunx @belt/ai hook" }
    11→ *
    12→ * Exit codes:
    13→ *   0 - Action allowed
    14→ *   2 - Action blocked
    15→ *   1 - Error
    16→ */
    17→
    18→import { existsSync } from 'fs';
    19→import { dirname, resolve } from 'path';
    20→import type {
    21→  AgentConfig,
    22→  AgentHookContext,
    23→  AgentRule,
    24→  RuleContext,
    25→} from './types';
    26→
    27→const DEBUG = process.env.BELT_AI_DEBUG === '1';
    28→const DEBUG_LOG = '/tmp/agentrc-runner-debug.log';
    29→const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();
    30→const AGENTRC_FILES = [
    31→  '.agentrc.ts',
    32→  'agentrc.ts',
    33→  '.agentrc.js',
    34→  'agentrc.js',
    35→];
    36→
    37→async function logDebug(message: string): Promise<void> {
    38→  if (!DEBUG) return;
    39→
    40→  const timestamp = new Date().toISOString();
    41→  const line = `[${timestamp}] ${message}\n`;
    42→
    43→  const { appendFileSync } = await import('fs');
    44→  appendFileSync(DEBUG_LOG, line);
    45→}
    46→
    47→async function readStdin(): Promise<string> {
    48→  if (typeof Bun !== 'undefined') {
    49→    return Bun.stdin.text();
    50→  }
    51→
    52→  // Node.js fallback
    53→  return new Promise((resolve, reject) => {
