#!/usr/bin/env node

/**
 * AgentRC Hook Runner
 *
 * Standalone CLI for evaluating .agentrc.ts rules during Claude Code hooks.
 * Called directly from settings.json without needing local wrapper files.
 *
 * Usage in .claude/settings.json:
 *   { "type": "command", "command": "bunx @belt/ai hook" }
 *
 * Exit codes:
 *   0 - Action allowed
 *   2 - Action blocked
 *   1 - Error
 */

import { existsSync } from 'fs';
import { dirname, resolve } from 'path';
import type {
  AgentConfig,
  AgentHookContext,
  AgentRule,
  RuleContext,
} from './types';

const DEBUG = process.env.BELT_AI_DEBUG === '1';
const DEBUG_LOG = '/tmp/agentrc-runner-debug.log';
const PROJECT_ROOT = process.env.CLAUDE_PROJECT_DIR || process.cwd();
const AGENTRC_FILES = [
  '.agentrc.ts',
  'agentrc.ts',
  '.agentrc.js',
  'agentrc.js',
];

async function logDebug(message: string): Promise<void> {
  if (!DEBUG) return;

  const timestamp = new Date().toISOString();
  const line = `[${timestamp}] ${message}\n`;

  const { appendFileSync } = await import('fs');
  appendFileSync(DEBUG_LOG, line);
}

async function readStdin(): Promise<string> {
  if (typeof Bun !== 'undefined') {
    return Bun.stdin.text();
  }

  // Node.js fallback
  return new Promise((resolve, reject) => {
    let data = '';
    process.stdin.setEncoding('utf8');
    process.stdin.on('data', chunk => (data += chunk));
    process.stdin.on('end', () => resolve(data));
    process.stdin.on('error', reject);
  });
}

async function findAgentrcFiles(startDir: string): Promise<string[]> {
  const files: string[] = [];
  let currentDir = startDir;

  while (
    currentDir.startsWith(PROJECT_ROOT) &&
    currentDir !== '/' &&
    currentDir.length >= PROJECT_ROOT.length
  ) {
    for (const filename of AGENTRC_FILES) {
      const filePath = resolve(currentDir, filename);
      if (existsSync(filePath)) {
        files.push(filePath);
        break;
      }
    }
    const parent = dirname(currentDir);
    if (parent === currentDir) break;
    currentDir = parent;
  }

  return files.reverse();
}

async function loadAndMergeConfigs(files: string[]): Promise<AgentConfig> {
  let mergedConfig: AgentConfig = {
    rules: [],
    hooks: {},
  };

  for (const file of files) {
    try {
      await logDebug(`Loading: ${file}`);
      const module = await import(file);
      const config: AgentConfig = module.default || module;

      if (typeof config.extend === 'function') {
        mergedConfig = config.extend(mergedConfig);
      } else {
        if (config.rules) {
          mergedConfig.rules = [
            ...(mergedConfig.rules || []),
            ...config.rules,
          ];
        }
        if (config.hooks) {
          mergedConfig.hooks = {
            ...mergedConfig.hooks,
            ...config.hooks,
          };
        }
      }
    } catch (err) {
      await logDebug(`Error loading ${file}: ${err}`);
    }
  }

  return mergedConfig;
}

async function evaluateRuleMatch(
  rule: AgentRule,
  filePath: string,
  ctx: RuleContext,
): Promise<boolean> {
  const { match } = rule;

  if (typeof match === 'string') return filePath.includes(match);
  if (match instanceof RegExp) return match.test(filePath);
  if (typeof match === 'function') return await match(filePath, ctx);

  return false;
}

async function main(): Promise<void> {
  await logDebug('=== AGENTRC HOOK RUNNER START ===');

  let stdinJson: string;
  try {
    stdinJson = await readStdin();
    await logDebug(`STDIN: ${stdinJson.substring(0, 200)}...`);
  } catch {
    process.exit(0);
  }

  let toolName: string;
  let toolInput: Record<string, unknown>;
  let filePath: string | undefined;

  try {
    const parsed = JSON.parse(stdinJson);
    toolName = parsed.tool_name || 'unknown';
    toolInput = parsed.tool_input || {};
    filePath = toolInput.file_path as string | undefined;
  } catch {
    process.exit(0);
  }

  await logDebug(`Tool: ${toolName}, FilePath: ${filePath || 'none'}`);

  if (!filePath) {
    process.exit(0);
  }

  const targetDir = dirname(filePath);
  const agentrcFiles = await findAgentrcFiles(targetDir);
  await logDebug(`Found ${agentrcFiles.length} agentrc files`);

  if (agentrcFiles.length === 0) {
    process.exit(0);
  }

  const config = await loadAndMergeConfigs(agentrcFiles);

  const ruleCtx: RuleContext = {
    tool: toolName,
    input: toolInput,
    projectRoot: PROJECT_ROOT,
  };

  for (const rule of config.rules || []) {
    const matches = await evaluateRuleMatch(rule, filePath, ruleCtx);

    if (matches) {
      await logDebug(`Rule ${rule.id} matched: ${rule.action}`);

      if (rule.action === 'block') {
        console.error(`\n❌ RULE VIOLATION: ${rule.id}`);
        console.error(`   ${rule.message || 'Action blocked'}`);
        console.error(`   File: ${filePath}\n`);
        process.exit(2);
      }

      if (rule.action === 'warn') {
        console.error(`\n⚠️  WARNING: ${rule.id}`);
        console.error(`   ${rule.message || 'Warning'}\n`);
      }
    }
  }

  if (config.hooks?.PreToolUse) {
    let blocked = false;
    let blockMessage = '';
    const injectedContent: string[] = [];

    const hookCtx: AgentHookContext = {
      tool: toolName,
      input: toolInput,
      projectRoot: PROJECT_ROOT,
      filePath,
      block: (msg: string) => {
        blocked = true;
        blockMessage = msg;
      },
      warn: (msg: string) => console.error(`⚠️  ${msg}`),
      inject: (content: string) => injectedContent.push(content),
    };

    try {
      await config.hooks.PreToolUse(hookCtx);
    } catch (err) {
      await logDebug(`Hook error: ${err}`);
    }

    if (injectedContent.length > 0) {
      console.log(injectedContent.join('\n'));
    }

    if (blocked) {
      console.error(`\n❌ BLOCKED: ${blockMessage}`);
      process.exit(2);
    }
  }

  await logDebug(`ALLOWED: ${filePath}`);
  process.exit(0);
}

main().catch(err => {
  console.error(`Runner error: ${err}`);
  process.exit(1);
});

