     1→/**
     2→ * Terminal Progress UI
     3→ *
     4→ * Multi-progress bar display for parallel downloads.
     5→ * Renders real-time progress with ANSI escape codes.
     6→ */
     7→
     8→import {
     9→  ModelDownload,
    10→  OllamaDownloadManager,
    11→  formatBytes,
    12→} from './download-manager';
    13→
    14→export interface ProgressUIConfig {
    15→  showTotal?: boolean;
    16→  barWidth?: number;
    17→  refreshIntervalMs?: number;
    18→  showSpeed?: boolean;
    19→}
    20→
    21→const DEFAULT_CONFIG: Required<ProgressUIConfig> = {
    22→  showTotal: true,
    23→  barWidth: 30,
    24→  refreshIntervalMs: 100,
    25→  showSpeed: true,
    26→};
    27→
    28→// ANSI escape codes
    29→const ANSI = {
    30→  clearLine: '\x1b[2K',
    31→  moveUp: (n: number) => `\x1b[${n}A`,
    32→  moveDown: (n: number) => `\x1b[${n}B`,
    33→  moveTo: (col: number) => `\x1b[${col}G`,
    34→  hide: '\x1b[?25l',
    35→  show: '\x1b[?25h',
    36→  reset: '\x1b[0m',
    37→  bold: '\x1b[1m',
    38→  dim: '\x1b[2m',
    39→  green: '\x1b[32m',
    40→  yellow: '\x1b[33m',
    41→  red: '\x1b[31m',
    42→  blue: '\x1b[34m',
    43→  cyan: '\x1b[36m',
    44→};
    45→
    46→interface SpeedTracker {
    47→  lastBytes: number;
    48→  lastTime: number;
    49→  speed: number;
    50→}
    51→
    52→/**
    53→ * Create progress bar string
    54→ */
    55→function createProgressBar(progress: number, width: number): string {
    56→  const filled = Math.round((progress / 100) * width);
    57→  const empty = width - filled;
    58→
    59→  const filledChar = '█';
    60→  const emptyChar = '░';
    61→
    62→  return filledChar.repeat(filled) + emptyChar.repeat(empty);
    63→}
    64→
    65→/**
    66→ * Get status color based on download status
    67→ */
    68→function getStatusColor(status: ModelDownload['status']): string {
    69→  switch (status) {
    70→    case 'completed':
    71→      return ANSI.green;
    72→    case 'downloading':
    73→      return ANSI.cyan;
    74→    case 'error':
    75→      return ANSI.red;
    76→    case 'pending':
    77→    default:
    78→      return ANSI.dim;
    79→  }
    80→}
    81→
    82→/**
    83→ * Get status icon
    84→ */
    85→function getStatusIcon(status: ModelDownload['status']): string {
    86→  switch (status) {
    87→    case 'completed':
    88→      return '✓';
    89→    case 'downloading':
    90→      return '↓';
    91→    case 'error':
    92→      return '✗';
    93→    case 'pending':
    94→    default:
    95→      return '○';
    96→  }
    97→}
    98→
    99→/**
   100→ * Format speed for display
   101→ */
   102→function formatSpeed(bytesPerSecond: number): string {
   103→  if (bytesPerSecond === 0) return '-- /s';
   104→  return `${formatBytes(bytesPerSecond)}/s`;
   105→}
   106→
   107→/**
   108→ * Truncate or pad string to fixed width
   109→ */
   110→function fixedWidth(str: string, width: number): string {
   111→  if (str.length > width) {
   112→    return str.substring(0, width - 1) + '…';
   113→  }
   114→  return str.padEnd(width);
   115→}
   116→
   117→export class DownloadProgressUI {
   118→  private config: Required<ProgressUIConfig>;
   119→  private manager: OllamaDownloadManager;
   120→  private models: string[] = [];
   121→  private linesWritten = 0;
   122→  private intervalId: NodeJS.Timeout | null = null;
   123→  private speedTrackers: Map<string, SpeedTracker> = new Map();
   124→  private startTime = 0;
   125→
   126→  constructor(manager: OllamaDownloadManager, config: ProgressUIConfig = {}) {
   127→    this.config = {
   128→      ...DEFAULT_CONFIG,
   129→      ...config,
   130→    };
   131→    this.manager = manager;
   132→    this.setupListeners();
   133→  }
   134→
   135→  /**
   136→   * Setup event listeners on the download manager
   137→   */
   138→  private setupListeners(): void {
   139→    this.manager.on('allStarted', () => {
   140→      this.startTime = Date.now();
   141→    });
   142→
   143→    this.manager.on('progress', (model, progress) => {
   144→      this.updateSpeed(model, progress.bytesDownloaded);
   145→    });
   146→  }
   147→
   148→  /**
   149→   * Update speed tracker for a model
   150→   */
   151→  private updateSpeed(model: string, bytesDownloaded: number): void {
   152→    const now = Date.now();
   153→    const tracker = this.speedTrackers.get(model);
   154→
   155→    if (!tracker) {
   156→      this.speedTrackers.set(model, {
   157→        lastBytes: bytesDownloaded,
   158→        lastTime: now,
   159→        speed: 0,
   160→      });
   161→      return;
   162→    }
   163→
   164→    const timeDiff = (now - tracker.lastTime) / 1000;
   165→    if (timeDiff >= 0.5) {
   166→      // Update every 500ms
   167→      const bytesDiff = bytesDownloaded - tracker.lastBytes;
   168→      tracker.speed = bytesDiff / timeDiff;
   169→      tracker.lastBytes = bytesDownloaded;
   170→      tracker.lastTime = now;
   171→    }
   172→  }
   173→
   174→  /**
   175→   * Start displaying progress
   176→   */
   177→  start(models: string[]): void {
   178→    this.models = models;
   179→    this.linesWritten = 0;
   180→
   181→    // Initialize speed trackers
   182→    for (const model of models) {
   183→      this.speedTrackers.set(model, {
   184→        lastBytes: 0,
   185→        lastTime: Date.now(),
   186→        speed: 0,
   187→      });
   188→    }
   189→
   190→    // Hide cursor
   191→    process.stdout.write(ANSI.hide);
   192→
   193→    // Print header
   194→    console.log(`\n${ANSI.bold}Downloading Ollama models...${ANSI.reset}\n`);
   195→    this.linesWritten = 2;
   196→
   197→    // Initial render
   198→    this.render();
   199→
   200→    // Start refresh interval
   201→    this.intervalId = setInterval(() => {
   202→      this.render();
   203→    }, this.config.refreshIntervalMs);
   204→  }
   205→
   206→  /**
   207→   * Stop displaying progress
   208→   */
   209→  stop(): void {
   210→    if (this.intervalId) {
   211→      clearInterval(this.intervalId);
   212→      this.intervalId = null;
   213→    }
   214→
   215→    // Final render
   216→    this.render();
   217→
   218→    // Show cursor
   219→    process.stdout.write(ANSI.show);
   220→
   221→    // Print summary
   222→    this.printSummary();
   223→  }
   224→
   225→  /**
   226→   * Render progress bars
   227→   */
   228→  private render(): void {
   229→    const status = this.manager.getStatus();
   230→
   231→    // Move cursor up to overwrite previous output
   232→    if (this.linesWritten > 2) {
   233→      process.stdout.write(ANSI.moveUp(this.linesWritten - 2));
   234→    }
   235→
   236→    const lines: string[] = [];
   237→
   238→    // Render each model
   239→    for (const model of this.models) {
   240→      const download = status.get(model);
   241→      if (!download) continue;
   242→
   243→      const line = this.formatModelLine(download);
   244→      lines.push(line);
   245→    }
   246→
   247→    // Render total progress if enabled
   248→    if (this.config.showTotal && this.models.length > 1) {
   249→      lines.push(''); // Empty line
   250→      lines.push(this.formatTotalLine());
   251→    }
   252→
   253→    // Write lines
   254→    for (const line of lines) {
   255→      process.stdout.write(ANSI.clearLine + line + '\n');
   256→    }
   257→
   258→    this.linesWritten = 2 + lines.length;
   259→  }
   260→
   261→  /**
   262→   * Format a single model line
   263→   */
   264→  private formatModelLine(download: ModelDownload): string {
   265→    const nameWidth = 22;
   266→    const name = fixedWidth(download.name, nameWidth);
   267→
   268→    const statusColor = getStatusColor(download.status);
   269→    const icon = getStatusIcon(download.status);
   270→
   271→    const bar = createProgressBar(download.progress, this.config.barWidth);
   272→    const progressStr = `${download.progress}%`.padStart(4);
   273→
   274→    let sizeStr = '';
   275→    if (download.totalBytes > 0) {
   276→      sizeStr = `${formatBytes(download.bytesDownloaded)}/${formatBytes(download.totalBytes)}`;
   277→    } else if (download.status === 'pending') {
   278→      sizeStr = 'queued';
   279→    } else if (download.status === 'error') {
   280→      sizeStr = download.error?.message.substring(0, 20) || 'error';
   281→    }
   282→    sizeStr = sizeStr.padStart(18);
   283→
   284→    let speedStr = '';
   285→    if (this.config.showSpeed && download.status === 'downloading') {
   286→      const tracker = this.speedTrackers.get(download.name);
   287→      if (tracker) {
   288→        speedStr = ` ${formatSpeed(tracker.speed)}`.padStart(12);
   289→      }
   290→    }
   291→
   292→    return `${statusColor}${icon}${ANSI.reset} ${name} [${bar}] ${progressStr} ${sizeStr}${speedStr}`;
   293→  }
   294→
   295→  /**
   296→   * Format total progress line
   297→   */
   298→  private formatTotalLine(): string {
   299→    const agg = this.manager.getAggregateProgress();
   300→
   301→    const label = 'Total'.padEnd(22);
   302→    const bar = createProgressBar(agg.progress, this.config.barWidth);
   303→    const progressStr = `${agg.progress}%`.padStart(4);
   304→    const sizeStr =
   305→      `${formatBytes(agg.downloadedBytes)}/${formatBytes(agg.totalBytes)}`.padStart(
   306→        18,
   307→      );
   308→
   309→    const statusStr = `(${agg.completed}/${agg.total} done)`;
   310→
   311→    return `${ANSI.bold}  ${label} [${bar}] ${progressStr} ${sizeStr} ${statusStr}${ANSI.reset}`;
   312→  }
