/**
 * Terminal Progress UI
 *
 * Multi-progress bar display for parallel downloads.
 * Renders real-time progress with ANSI escape codes.
 */

import {
  ModelDownload,
  OllamaDownloadManager,
  formatBytes,
} from './download-manager';

export interface ProgressUIConfig {
  showTotal?: boolean;
  barWidth?: number;
  refreshIntervalMs?: number;
  showSpeed?: boolean;
}

const DEFAULT_CONFIG: Required<ProgressUIConfig> = {
  showTotal: true,
  barWidth: 30,
  refreshIntervalMs: 100,
  showSpeed: true,
};

// ANSI escape codes
const ANSI = {
  clearLine: '\x1b[2K',
  moveUp: (n: number) => `\x1b[${n}A`,
  moveDown: (n: number) => `\x1b[${n}B`,
  moveTo: (col: number) => `\x1b[${col}G`,
  hide: '\x1b[?25l',
  show: '\x1b[?25h',
  reset: '\x1b[0m',
  bold: '\x1b[1m',
  dim: '\x1b[2m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  red: '\x1b[31m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
};

interface SpeedTracker {
  lastBytes: number;
  lastTime: number;
  speed: number;
}

/**
 * Create progress bar string
 */
function createProgressBar(progress: number, width: number): string {
  const filled = Math.round((progress / 100) * width);
  const empty = width - filled;

  const filledChar = '█';
  const emptyChar = '░';

  return filledChar.repeat(filled) + emptyChar.repeat(empty);
}

/**
 * Get status color based on download status
 */
function getStatusColor(status: ModelDownload['status']): string {
  switch (status) {
    case 'completed':
      return ANSI.green;
    case 'downloading':
      return ANSI.cyan;
    case 'error':
      return ANSI.red;
    case 'pending':
    default:
      return ANSI.dim;
  }
}

/**
 * Get status icon
 */
function getStatusIcon(status: ModelDownload['status']): string {
  switch (status) {
    case 'completed':
      return '✓';
    case 'downloading':
      return '↓';
    case 'error':
      return '✗';
    case 'pending':
    default:
      return '○';
  }
}

/**
 * Format speed for display
 */
function formatSpeed(bytesPerSecond: number): string {
  if (bytesPerSecond === 0) return '-- /s';
  return `${formatBytes(bytesPerSecond)}/s`;
}

/**
 * Truncate or pad string to fixed width
 */
function fixedWidth(str: string, width: number): string {
  if (str.length > width) {
    return str.substring(0, width - 1) + '…';
  }
  return str.padEnd(width);
}

export class DownloadProgressUI {
  private config: Required<ProgressUIConfig>;
  private manager: OllamaDownloadManager;
  private models: string[] = [];
  private linesWritten = 0;
  private intervalId: NodeJS.Timeout | null = null;
  private speedTrackers: Map<string, SpeedTracker> = new Map();
  private startTime = 0;

  constructor(manager: OllamaDownloadManager, config: ProgressUIConfig = {}) {
    this.config = {
      ...DEFAULT_CONFIG,
      ...config,
    };
    this.manager = manager;
    this.setupListeners();
  }

  /**
   * Setup event listeners on the download manager
   */
  private setupListeners(): void {
    this.manager.on('allStarted', () => {
      this.startTime = Date.now();
    });

    this.manager.on('progress', (model, progress) => {
      this.updateSpeed(model, progress.bytesDownloaded);
    });
  }

  /**
   * Update speed tracker for a model
   */
  private updateSpeed(model: string, bytesDownloaded: number): void {
    const now = Date.now();
    const tracker = this.speedTrackers.get(model);

    if (!tracker) {
      this.speedTrackers.set(model, {
        lastBytes: bytesDownloaded,
        lastTime: now,
        speed: 0,
      });
      return;
    }

    const timeDiff = (now - tracker.lastTime) / 1000;
    if (timeDiff >= 0.5) {
      // Update every 500ms
      const bytesDiff = bytesDownloaded - tracker.lastBytes;
      tracker.speed = bytesDiff / timeDiff;
      tracker.lastBytes = bytesDownloaded;
      tracker.lastTime = now;
    }
  }

  /**
   * Start displaying progress
   */
  start(models: string[]): void {
    this.models = models;
    this.linesWritten = 0;

    // Initialize speed trackers
    for (const model of models) {
      this.speedTrackers.set(model, {
        lastBytes: 0,
        lastTime: Date.now(),
        speed: 0,
      });
    }

    // Hide cursor
    process.stdout.write(ANSI.hide);

    // Print header
    console.log(`\n${ANSI.bold}Downloading Ollama models...${ANSI.reset}\n`);
    this.linesWritten = 2;

    // Initial render
    this.render();

    // Start refresh interval
    this.intervalId = setInterval(() => {
      this.render();
    }, this.config.refreshIntervalMs);
  }

  /**
   * Stop displaying progress
   */
  stop(): void {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }

    // Final render
    this.render();

    // Show cursor
    process.stdout.write(ANSI.show);

    // Print summary
    this.printSummary();
  }

  /**
   * Render progress bars
   */
  private render(): void {
    const status = this.manager.getStatus();

    // Move cursor up to overwrite previous output
    if (this.linesWritten > 2) {
      process.stdout.write(ANSI.moveUp(this.linesWritten - 2));
    }

    const lines: string[] = [];

    // Render each model
    for (const model of this.models) {
      const download = status.get(model);
      if (!download) continue;

      const line = this.formatModelLine(download);
      lines.push(line);
    }

    // Render total progress if enabled
    if (this.config.showTotal && this.models.length > 1) {
      lines.push(''); // Empty line
      lines.push(this.formatTotalLine());
    }

    // Write lines
    for (const line of lines) {
      process.stdout.write(ANSI.clearLine + line + '\n');
    }

    this.linesWritten = 2 + lines.length;
  }

  /**
   * Format a single model line
   */
  private formatModelLine(download: ModelDownload): string {
    const nameWidth = 22;
    const name = fixedWidth(download.name, nameWidth);

    const statusColor = getStatusColor(download.status);
    const icon = getStatusIcon(download.status);

    const bar = createProgressBar(download.progress, this.config.barWidth);
    const progressStr = `${download.progress}%`.padStart(4);

    let sizeStr = '';
    if (download.totalBytes > 0) {
      sizeStr = `${formatBytes(download.bytesDownloaded)}/${formatBytes(download.totalBytes)}`;
    } else if (download.status === 'pending') {
      sizeStr = 'queued';
    } else if (download.status === 'error') {
      sizeStr = download.error?.message.substring(0, 20) || 'error';
    }
    sizeStr = sizeStr.padStart(18);

    let speedStr = '';
    if (this.config.showSpeed && download.status === 'downloading') {
      const tracker = this.speedTrackers.get(download.name);
      if (tracker) {
        speedStr = ` ${formatSpeed(tracker.speed)}`.padStart(12);
      }
    }

    return `${statusColor}${icon}${ANSI.reset} ${name} [${bar}] ${progressStr} ${sizeStr}${speedStr}`;
  }

  /**
   * Format total progress line
   */
  private formatTotalLine(): string {
    const agg = this.manager.getAggregateProgress();

    const label = 'Total'.padEnd(22);
    const bar = createProgressBar(agg.progress, this.config.barWidth);
    const progressStr = `${agg.progress}%`.padStart(4);
    const sizeStr =
      `${formatBytes(agg.downloadedBytes)}/${formatBytes(agg.totalBytes)}`.padStart(
        18,
      );

    const statusStr = `(${agg.completed}/${agg.total} done)`;

    return `${ANSI.bold}  ${label} [${bar}] ${progressStr} ${sizeStr} ${statusStr}${ANSI.reset}`;
  }

  /**
   * Print final summary
   */
  private printSummary(): void {
    const agg = this.manager.getAggregateProgress();
    const duration = ((Date.now() - this.startTime) / 1000).toFixed(1);

    console.log('');

    if (agg.failed === 0) {
      console.log(
        `${ANSI.green}✓${ANSI.reset} All ${agg.total} models downloaded successfully in ${duration}s`,
      );
    } else {
      console.log(
        `${ANSI.yellow}!${ANSI.reset} Downloaded ${agg.completed}/${agg.total} models (${agg.failed} failed) in ${duration}s`,
      );

      // List failed models
      const status = this.manager.getStatus();
      for (const [model, download] of status) {
        if (download.status === 'error') {
          console.log(
            `  ${ANSI.red}✗${ANSI.reset} ${model}: ${download.error?.message || 'Unknown error'}`,
          );
        }
      }
    }

    console.log('');
  }
}

/**
 * Create and run progress UI for a download manager
 */
export async function runWithProgressUI(
  manager: OllamaDownloadManager,
  models: string[],
  config?: ProgressUIConfig,
): Promise<Map<string, ModelDownload>> {
  const ui = new DownloadProgressUI(manager, config);

  ui.start(models);

  try {
    const results = await manager.pullModels(models);
    return results;
  } finally {
    ui.stop();
  }
}

/**
 * Simple text-based progress (no ANSI, for non-TTY)
 */
export function runWithSimpleProgress(
  manager: OllamaDownloadManager,
  models: string[],
): Promise<Map<string, ModelDownload>> {
  console.log(`\nDownloading ${models.length} Ollama models...\n`);

  manager.on('started', model => {
    console.log(`  ↓ Starting: ${model}`);
  });

  manager.on('completed', (model, result) => {
    if (result.success) {
      console.log(
        `  ✓ Completed: ${model} (${(result.duration / 1000).toFixed(1)}s)`,
      );
    }
  });

  manager.on('error', (model, error) => {
    console.log(`  ✗ Failed: ${model} - ${error.message}`);
  });

  manager.on('retry', (model, attempt, delay) => {
    console.log(
      `  ↻ Retrying: ${model} (attempt ${attempt}, waiting ${delay}ms)`,
    );
  });

  return manager.pullModels(models);
}

/**
 * Run progress UI with automatic TTY detection
 */
export async function runWithAutoProgress(
  manager: OllamaDownloadManager,
  models: string[],
  config?: ProgressUIConfig,
): Promise<Map<string, ModelDownload>> {
  const isTTY = process.stdout.isTTY;

  if (isTTY) {
    return runWithProgressUI(manager, models, config);
  } else {
    return runWithSimpleProgress(manager, models);
  }
}

