   164→}
   165→
   166→/**
   167→ * Execute an agent with a given prompt
   168→ */
   169→export async function executeAgent(
   170→  agentId: string,
   171→  prompt: string,
   172→  context?: string,
   173→  options: AgentExecutionOptions = {}
   174→): Promise<AgentResponse> {
   175→  const agent = getAgent(agentId);
   176→
   177→  if (!agent) {
   178→    return {
   179→      agentId,
   180→      content: '',
   181→      model: 'unknown',
   182→      success: false,
   183→      error: `Agent not found: ${agentId}`,
   184→    };
   185→  }
   186→
   187→  const client = options.client || createOllamaClient();
   188→
   189→  // Check if Ollama is running
   190→  const isRunning = await client.isRunning();
   191→  if (!isRunning) {
   192→    return {
   193→      agentId,
   194→      content: '',
   195→      model: agent.model,
   196→      success: false,
   197→      error: 'Ollama is not running. Start it with: ollama serve',
   198→    };
   199→  }
   200→
   201→  // Check if model is available
   202→  const hasModel = await client.hasModel(agent.model);
   203→  if (!hasModel) {
   204→    return {
   205→      agentId,
   206→      content: '',
   207→      model: agent.model,
   208→      success: false,
   209→      error: `Model not available: ${agent.model}. Pull it with: ollama pull ${agent.model}`,
   210→    };
   211→  }
   212→
   213→  // Build messages
   214→  const messages: OllamaChatMessage[] = [
   215→    {
   216→      role: 'system',
   217→      content: agent.systemPrompt,
   218→    },
   219→  ];
   220→
   221→  if (context) {
   222→    messages.push({
   223→      role: 'user',
   224→      content: `Context:\n${context}`,
   225→    });
   226→  }
   227→
   228→  messages.push({
   229→    role: 'user',
   230→    content: prompt,
   231→  });
   232→
   233→  // Execute
   234→  try {
   235→    const response = await client.chat({
   236→      model: agent.model,
   237→      messages,
   238→      temperature: options.temperature ?? 0.7,
   239→      numPredict: options.maxTokens ?? 2000,
   240→    });
   241→
   242→    if (!response) {
   243→      return {
   244→        agentId,
   245→        content: '',
   246→        model: agent.model,
   247→        success: false,
   248→        error: 'No response from model',
   249→      };
   250→    }
   251→
   252→    return {
   253→      agentId,
   254→      content: response.message.content,
   255→      model: agent.model,
   256→      success: true,
   257→    };
   258→  } catch (error) {
   259→    return {
   260→      agentId,
   261→      content: '',
   262→      model: agent.model,
   263→      success: false,
   264→      error: error instanceof Error ? error.message : 'Unknown error',
   265→    };
   266→  }
   267→}
   268→
   269→/**
   270→ * Stream agent response
   271→ */
   272→export async function* streamAgent(
   273→  agentId: string,
   274→  prompt: string,
   275→  context?: string,
   276→  options: AgentExecutionOptions = {}
   277→): AsyncGenerator<
   278→  {
   279→    content: string;
   280→    done: boolean;
   281→  },
   282→  void,
   283→  unknown
   284→> {
   285→  const agent = getAgent(agentId);
   286→
   287→  if (!agent) {
   288→    yield {
   289→      content: `Error: Agent not found: ${agentId}`,
   290→      done: true,
   291→    };
   292→    return;
   293→  }
   294→
   295→  const client = options.client || createOllamaClient();
   296→
   297→  // Check if Ollama is running
   298→  const isRunning = await client.isRunning();
   299→  if (!isRunning) {
   300→    yield {
   301→      content: 'Error: Ollama is not running. Start it with: ollama serve',
   302→      done: true,
   303→    };
   304→    return;
   305→  }
   306→
   307→  // Build messages
