/**
 * Belt Harness Agents
 *
 * Agent definitions and execution for the harness system.
 * Implements the agent architecture from hard-harness-example.md.
 */

import { createOllamaClient, OllamaChatMessage, OllamaClient } from '../ollama';

export interface Agent {
  id: string;
  name: string;
  model: string;
  systemPrompt: string;
  capabilities: string[];
}

export interface AgentResponse {
  agentId: string;
  content: string;
  model: string;
  success: boolean;
  error?: string;
}

export interface AgentExecutionOptions {
  client?: OllamaClient;
  temperature?: number;
  maxTokens?: number;
}

export const AGENTS: Record<string, Agent> = {
  'project-manager': {
    id: 'project-manager',
    name: 'Project Manager',
    model: 'deepseek-r1:8b',
    systemPrompt: `You are a project manager for a software development project.
Your role is to:
- Manage the backlog and prioritize features
- Track progress and update status
- Coordinate between different aspects of the project
- Ensure milestones are met
- Break down large tasks into smaller, actionable items

Communication style:
- Be concise and action-oriented
- Use bullet points for lists
- Provide clear next steps
- Focus on what needs to be done, not how long it takes

Output format:
- Use markdown for structure
- Keep responses under 500 words unless detailed analysis is requested`,
    capabilities: [
      'backlog',
      'prioritization',
      'status',
      'planning',
      'decomposition',
    ],
  },
  'tech-lead': {
    id: 'tech-lead',
    name: 'Tech Lead',
    model: 'deepseek-r1:8b',
    systemPrompt: `You are a tech lead for a software development project.
Your role is to:
- Make architectural decisions
- Review code and designs
- Ensure code quality and best practices
- Guide technical implementation
- Identify technical risks and dependencies

Technical principles:
- Prefer simplicity over cleverness
- Prioritize maintainability
- Follow existing patterns in the codebase
- Avoid over-engineering
- Consider production readiness

Output format:
- Use markdown for structure
- Include code examples when relevant
- Explain trade-offs clearly`,
    capabilities: [
      'architecture',
      'review',
      'decisions',
      'quality',
      'technical-guidance',
    ],
  },
  'product-owner': {
    id: 'product-owner',
    name: 'Product Owner',
    model: 'deepseek-r1:8b',
    systemPrompt: `You are a product owner for a software development project.
Your role is to:
- Define requirements and user stories
- Create acceptance criteria
- Prioritize features based on value
- Represent the user's perspective
- Clarify scope and edge cases

Focus areas:
- User value and outcomes
- Clear, testable requirements
- Minimum viable scope
- Edge cases and error states

Output format:
- Use markdown for structure
- Write user stories in "As a... I want... So that..." format
- List acceptance criteria as checkboxes
- Be specific about success criteria`,
    capabilities: [
      'requirements',
      'stories',
      'criteria',
      'prioritization',
      'user-focus',
    ],
  },
  'code-reviewer': {
    id: 'code-reviewer',
    name: 'Code Reviewer',
    model: 'qwen2.5-coder:7b',
    systemPrompt: `You are a code reviewer for a software development project.
Your role is to:
- Review code for bugs and issues
- Check for security vulnerabilities
- Ensure code follows best practices
- Suggest improvements and refactoring
- Verify test coverage

Review criteria:
- Correctness: Does the code do what it should?
- Security: Are there any vulnerabilities?
- Performance: Are there obvious inefficiencies?
- Maintainability: Is the code clear and well-structured?
- Testing: Is the code adequately tested?

Output format:
- Use markdown for structure
- Group issues by severity (Critical, Warning, Suggestion)
- Include line references when possible
- Provide specific fix recommendations`,
    capabilities: [
      'review',
      'bugs',
      'security',
      'quality',
      'suggestions',
    ],
  },
};

export function getAgent(agentId: string): Agent | undefined {
  return AGENTS[agentId];
}

export function listAgents(): Agent[] {
  return Object.values(AGENTS);
}

/**
 * Execute an agent with a given prompt
 */
export async function executeAgent(
  agentId: string,
  prompt: string,
  context?: string,
  options: AgentExecutionOptions = {}
): Promise<AgentResponse> {
  const agent = getAgent(agentId);

  if (!agent) {
    return {
      agentId,
      content: '',
      model: 'unknown',
      success: false,
      error: `Agent not found: ${agentId}`,
    };
  }

  const client = options.client || createOllamaClient();

  // Check if Ollama is running
  const isRunning = await client.isRunning();
  if (!isRunning) {
    return {
      agentId,
      content: '',
      model: agent.model,
      success: false,
      error: 'Ollama is not running. Start it with: ollama serve',
    };
  }

  // Check if model is available
  const hasModel = await client.hasModel(agent.model);
  if (!hasModel) {
    return {
      agentId,
      content: '',
      model: agent.model,
      success: false,
      error: `Model not available: ${agent.model}. Pull it with: ollama pull ${agent.model}`,
    };
  }

  // Build messages
  const messages: OllamaChatMessage[] = [
    {
      role: 'system',
      content: agent.systemPrompt,
    },
  ];

  if (context) {
    messages.push({
      role: 'user',
      content: `Context:\n${context}`,
    });
  }

  messages.push({
    role: 'user',
    content: prompt,
  });

  // Execute
  try {
    const response = await client.chat({
      model: agent.model,
      messages,
      temperature: options.temperature ?? 0.7,
      numPredict: options.maxTokens ?? 2000,
    });

    if (!response) {
      return {
        agentId,
        content: '',
        model: agent.model,
        success: false,
        error: 'No response from model',
      };
    }

    return {
      agentId,
      content: response.message.content,
      model: agent.model,
      success: true,
    };
  } catch (error) {
    return {
      agentId,
      content: '',
      model: agent.model,
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error',
    };
  }
}

/**
 * Stream agent response
 */
export async function* streamAgent(
  agentId: string,
  prompt: string,
  context?: string,
  options: AgentExecutionOptions = {}
): AsyncGenerator<
  {
    content: string;
    done: boolean;
  },
  void,
  unknown
> {
  const agent = getAgent(agentId);

  if (!agent) {
    yield {
      content: `Error: Agent not found: ${agentId}`,
      done: true,
    };
    return;
  }

  const client = options.client || createOllamaClient();

  // Check if Ollama is running
  const isRunning = await client.isRunning();
  if (!isRunning) {
    yield {
      content: 'Error: Ollama is not running. Start it with: ollama serve',
      done: true,
    };
    return;
  }

  // Build messages
  const messages: OllamaChatMessage[] = [
    {
      role: 'system',
      content: agent.systemPrompt,
    },
  ];

  if (context) {
    messages.push({
      role: 'user',
      content: `Context:\n${context}`,
    });
  }

  messages.push({
    role: 'user',
    content: prompt,
  });

  // Stream
  for await (const chunk of client.streamChat({
    model: agent.model,
    messages,
    temperature: options.temperature ?? 0.7,
    numPredict: options.maxTokens ?? 2000,
  })) {
    yield chunk;
  }
}

/**
 * Execute multiple agents in sequence for collaborative analysis
 */
export async function collaborativeAnalysis(
  prompt: string,
  agentIds: string[] = [
    'product-owner',
    'tech-lead',
    'project-manager',
  ],
  context?: string,
  options: AgentExecutionOptions = {}
): Promise<AgentResponse[]> {
  const responses: AgentResponse[] = [];
  let accumulatedContext = context || '';

  for (const agentId of agentIds) {
    const response = await executeAgent(
      agentId,
      prompt,
      accumulatedContext,
      options,
    );
    responses.push(response);

    if (response.success) {
      accumulatedContext += `\n\n--- ${getAgent(agentId)?.name} Analysis ---\n${response.content}`;
    }
  }

  return responses;
}

