import {
	existsSync,
	readFileSync,
	statSync,
	unlinkSync,
	writeFileSync,
} from "node:fs";
import robot from "@jitsi/robotjs";
import { ensureConfigDir, LOG_FILE, PID_FILE } from "./paths.js";
import { incrementJiggle, incrementSkipped, markStarted } from "./stats.js";
import type { Config } from "./types.js";

const MAX_LOG_SIZE_BYTES = 5 * 1024 * 1024; // 5MB

export function getRandomInterval(
	baseMs: number,
	variancePercent = 0.3,
): number {
	const variance = baseMs * variancePercent;
	return Math.round(baseMs + (Math.random() * 2 - 1) * variance);
}

export function writePidFile(): void {
	ensureConfigDir();
	writeFileSync(PID_FILE, String(process.pid), "utf-8");
}

export function removePidFile(): void {
	if (existsSync(PID_FILE)) {
		unlinkSync(PID_FILE);
	}
}

export function readPidFile(): number | null {
	if (!existsSync(PID_FILE)) {
		return null;
	}
	try {
		const content = readFileSync(PID_FILE, "utf-8");
		return parseInt(content.trim(), 10);
	} catch {
		return null;
	}
}

export function isProcessRunning(pid: number): boolean {
	try {
		process.kill(pid, 0);
		return true;
	} catch {
		return false;
	}
}

export function isDaemonRunning(): {
	running: boolean;
	pid: number | null;
} {
	const pid = readPidFile();
	if (pid === null) {
		return {
			running: false,
			pid: null,
		};
	}
	const running = isProcessRunning(pid);
	if (!running) {
		removePidFile();
	}
	return {
		running,
		pid: running ? pid : null,
	};
}

export function getLogFile(): string {
	return LOG_FILE;
}

export function rotateLogIfNeeded(): void {
	try {
		if (!existsSync(LOG_FILE)) return;

		const stats = statSync(LOG_FILE);
		if (stats.size > MAX_LOG_SIZE_BYTES) {
			// Keep last 20% of the file
			const keepBytes = Math.floor(MAX_LOG_SIZE_BYTES * 0.2);
			const content = readFileSync(LOG_FILE, "utf-8");
			const truncated = content.slice(-keepBytes);
			writeFileSync(
				LOG_FILE,
				`[LOG ROTATED - kept last ${Math.round(keepBytes / 1024)}KB]\n${truncated}`,
			);
		}
	} catch {
		// Ignore rotation errors
	}
}

export class ComplianceDaemon {
	private intervalId: NodeJS.Timeout | null = null;
	private lastPos: {
		x: number;
		y: number;
	} | null = null;
	private lastActivityTime: number = Date.now();
	private logFile: string;
	private tickCount = 0;

	constructor(private config: Config) {
		this.logFile = LOG_FILE;
	}

	start(): void {
		writePidFile();
		markStarted();

		this.log("Starting Compliance Daemon...");
		this.log(
			`Config: interval=${this.config.intervalMs}ms, pixels=${this.config.movementPx}, mode=${this.config.mode}`,
		);
		this.log(`PID: ${process.pid}`);
		this.log(`Log file: ${this.logFile}`);

		this.scheduleNext();

		process.on("SIGINT", () => this.shutdown());
		process.on("SIGTERM", () => this.shutdown());
	}

	private scheduleNext(): void {
		const interval = getRandomInterval(this.config.intervalMs);
		this.log(`Next tick in ${interval}ms`);
		this.intervalId = setTimeout(() => {
			this.tick();
			this.scheduleNext();
		}, interval);
	}

	private tick(): void {
		this.tickCount++;

		// Check log rotation every 100 ticks
		if (this.tickCount % 100 === 0) {
			rotateLogIfNeeded();
		}

		if (!this.shouldActivate()) {
			this.log("User active, skipping...");
			incrementSkipped();
			return;
		}

		switch (this.config.mode) {
			case "mouse":
				this.jiggleMouse();
				break;
			case "keyboard":
				this.jiggleKeyboard();
				break;
			case "both":
				Math.random() > 0.5 ? this.jiggleMouse() : this.jiggleKeyboard();
				break;
		}
	}

	private jiggleMouse(): void {
		try {
			const { x, y } = robot.getMousePos();
			const angle = Math.random() * Math.PI * 2;
			const radius = this.config.movementPx;

			const newX = Math.round(x + Math.cos(angle) * radius);
			const newY = Math.round(y + Math.sin(angle) * radius);

			robot.moveMouse(newX, newY);

			setTimeout(
				() => {
					robot.moveMouse(x, y);
				},
				30 + Math.random() * 50,
			);

			this.log(`Mouse jiggle: (${x},${y}) → (${newX},${newY}) → (${x},${y})`);
			incrementJiggle("mouse");
		} catch (err) {
			this.logError("Mouse jiggle failed:", err);
			this.logError("Make sure Accessibility permission is granted");
		}
	}

	private jiggleKeyboard(): void {
		try {
			robot.keyToggle("shift", "down");
			robot.keyToggle("shift", "up");
			this.log("Keyboard jiggle: Shift press/release");
			incrementJiggle("keyboard");
		} catch (err) {
			this.logError("Keyboard jiggle failed:", err);
		}
	}

	private shouldActivate(): boolean {
		const currentPos = robot.getMousePos();

		if (
			this.lastPos &&
			(currentPos.x !== this.lastPos.x || currentPos.y !== this.lastPos.y)
		) {
			this.lastActivityTime = Date.now();
		}

		this.lastPos = currentPos;

		const idleTime = Date.now() - this.lastActivityTime;
		return idleTime > this.config.idleThresholdMs;
	}

	private log(message: string): void {
		if (this.config.verbose) {
			const timestamp = new Date().toISOString();
			const line = `[${timestamp}] ${message}`;
			console.log(line);
		}
	}

	private logError(message: string, err?: unknown): void {
		const timestamp = new Date().toISOString();
		const errorMsg = err instanceof Error ? err.message : String(err);
		console.error(
			`[${timestamp}] [ERROR] ${message}`,
			errorMsg ? errorMsg : "",
		);
	}

	private shutdown(): void {
		this.log("Shutting down...");
		if (this.intervalId) {
			clearTimeout(this.intervalId);
		}
		removePidFile();
		process.exit(0);
	}
}

